  ('disabled-7c4986e7-moex-00296', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-110-6948958a', 'sub-disabled-7c4986e7-01', NULL, 'single_choice', '假設不考慮國外部門。在簡單凱因斯模型裡，根據下列條件，當定額稅（T） 由40增為50時，均衡下的民間儲蓄會： 民間消費函數：C=10+0.8(Y-T) 計畫的民間投資：I=50 政府消費支出：G=20', '["增加12", "增加20", "減少8", "減少10"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:00+00:00", "source_pdf_sha1": "bdee1ccae880", "answer_pdf_sha1": "5625f3fd9f41", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "405", "s": "0910", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
