  ('disabled-7c4986e7-moex-00298', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-110-6948958a', 'sub-disabled-7c4986e7-01', NULL, 'single_choice', '下列有關貨幣市場與資本市場，何者敘述正確？', '["資本市場交易的是長期金融商品，而貨幣市場交易短期金融商品", "資本市場交易的是短期金融商品，而貨幣市場交易長期金融商品", "資本市場交易的金融商品價格波動較小，貨幣市場較大", "資本市場金融商品的流動性高於貨幣市場"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:00+00:00", "source_pdf_sha1": "bdee1ccae880", "answer_pdf_sha1": "5625f3fd9f41", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "405", "s": "0910", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00299', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-110-6948958a', 'sub-disabled-7c4986e7-01', NULL, 'single_choice', '下列何者為直接金融？', '["買入新上市股票1萬元", "買入某基金1萬元", "某公司向銀行借款1萬元", "向保險公司買入投資型保單1萬元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:00+00:00", "source_pdf_sha1": "bdee1ccae880", "answer_pdf_sha1": "5625f3fd9f41", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "405", "s": "0910", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
